from typing import List
from collections import deque

class Solution:
    def maxEnergyDivisibleByK(self, nums: List[int], n: int, k: int) -> int:
        # 每个余数维护一个单调队列，存储二元组：(前缀下标, 前缀和)
        queues = [deque() for _ in range(k)]

        # 初始前缀和为 0，下标为 0，余数为 0
        queues[0].append((0, 0))

        prefix = 0
        ans = -10**30
        found = False

        # 遍历复制后的数组，下标 r 表示当前前缀和位置
        for r in range(1, 2 * n + 1):
            prefix += nums[(r - 1) % n]
            # 处理负数取模
            mod = prefix % k

            q = queues[mod]

            # 删除长度超过 n 的旧前缀和
            while q and q[0][0] < r - n:
                q.popleft()

            # 队首是当前窗口内同余数的最小前缀和
            if q:
                ans = max(ans, prefix - q[0][1])
                found = True

            # 将当前前缀和加入对应余数的单调队列
            # 保持队列中的前缀和值单调递增
            while q and q[-1][1] >= prefix:
                q.pop()

            q.append((r, prefix))

        return ans if found else 0
```

```java
import java.util.*;

class Solution {
    public long maxEnergyDivisibleByK(int[] nums, int n, int k) {
        // 每个余数维护一个单调队列，队列元素为 long[]{前缀下标, 前缀和}
        ArrayDeque<long[]>[] queues = new ArrayDeque[k];

        for (int i = 0; i < k; i++) {
            queues[i] = new ArrayDeque<>();
        }

        // 初始前缀和为 0，下标为 0，余数为 0
        queues[0].offerLast(new long[]{0, 0});

        long prefix = 0;
        long ans = Long.MIN_VALUE;
        boolean found = false;

        // 遍历复制后的数组
        for (int r = 1; r <= 2 * n; r++) {
            prefix += nums[(r - 1) % n];

            int mod = getMod(prefix, k);
            ArrayDeque<long[]> q = queues[mod];

            // 删除长度超过 n 的旧前缀和
            while (!q.isEmpty() && q.peekFirst()[0] < r - n) {
                q.pollFirst();
            }

            // 队首是当前窗口内同余数的最小前缀和
            if (!q.isEmpty()) {
                ans = Math.max(ans, prefix - q.peekFirst()[1]);
                found = true;
            }

            // 将当前前缀和加入对应余数的单调队列
            // 保持队列中的前缀和值单调递增
            while (!q.isEmpty() && q.peekLast()[1] >= prefix) {
                q.pollLast();
            }

            q.offerLast(new long[]{r, prefix});
        }

        return found ? ans : 0;
    }

    // 处理负数取模
    private int getMod(long x, int k) {
        int res = (int)(x % k);
        if (res < 0) {
            res += k;
        }
        return res;
    }
}
