#include <vector>
#include <deque>
#include <climits>
using namespace std;

class Solution {
public:
    long long maxEnergyDivisibleByK(vector<int>& nums, int n, int k) {
        // 每个余数维护一个单调队列，存储 pair<前缀下标, 前缀和>
        vector<deque<pair<int, long long>>> queues(k);

        // 初始前缀和为 0，下标为 0，余数为 0
        queues[0].push_back({0, 0});

        long long prefix = 0;
        long long ans = LLONG_MIN;
        bool found = false;

        // 处理负数取模
        auto getMod = [&](long long x) {
            int res = x % k;
            if (res < 0) {
                res += k;
            }
            return res;
        };

        // 遍历复制后的数组
        for (int r = 1; r <= 2 * n; r++) {
            prefix += nums[(r - 1) % n];

            int mod = getMod(prefix);
            auto& q = queues[mod];

            // 删除长度超过 n 的旧前缀和
            while (!q.empty() && q.front().first < r - n) {
                q.pop_front();
            }

            // 队首是当前窗口内同余数的最小前缀和
            if (!q.empty()) {
                ans = max(ans, prefix - q.front().second);
                found = true;
            }

            // 将当前前缀和加入对应余数的单调队列
            // 保持队列中的前缀和值单调递增
            while (!q.empty() && q.back().second >= prefix) {
                q.pop_back();
            }

            q.push_back({r, prefix});
        }

        return found ? ans : 0;
    }
};
