/**
 * 环形数组最大能被 k 整除的子数组和
 * 算法：前缀和 + 同余分组 + 单调队列
 * 时间复杂度 O(n)，空间复杂度 O(n + k)
 *
 * @param {number[]} nums - 魔法石的能量值数组
 * @param {number} n - 魔法石数量
 * @param {number} k - 除数
 * @return {number} - 能被 k 整除的最大总能量值，若不存在则返回 0
 */
var maxEnergyDivisibleByK = function(nums, n, k) {
    // 每个余数维护一个单调队列，队列元素为 [前缀下标, 前缀和]
    const queues = Array.from({ length: k }, () => []);

    // 初始：前缀下标 0，前缀和 0，余数 0
    queues[0].push([0, 0]);

    let prefix = 0;
    let ans = -Infinity;
    let found = false;

    // 遍历复制后的数组（2n 长度），r 表示前缀和位置
    for (let r = 1; r <= 2 * n; r++) {
        prefix += nums[(r - 1) % n];
        // 处理负数取模
        const mod = ((prefix % k) + k) % k;

        const q = queues[mod];

        // 删除长度超过 n 的旧前缀和
        while (q.length > 0 && q[0][0] < r - n) {
            q.shift();
        }

        // 队首是当前窗口内同余数的最小前缀和
        if (q.length > 0) {
            ans = Math.max(ans, prefix - q[0][1]);
            found = true;
        }

        // 将当前前缀和加入单调队列，保持前缀和值单调递增
        while (q.length > 0 && q[q.length - 1][1] >= prefix) {
            q.pop();
        }
        q.push([r, prefix]);
    }

    return found ? ans : 0;
};
