```c
/**
 * 环形数组最大能被 k 整除的子数组和
 * 算法：前缀和 + 同余分组 + 单调队列
 * 时间复杂度 O(n)，空间复杂度 O(n + k)
 *
 * @param nums 魔法石能量值数组
 * @param n 魔法石数量
 * @param k 除数
 * @return 能被 k 整除的最大总能量值；若不存在则返回 0
 */
long long maxEnergyDivisibleByK(int* nums, int n, int k) {
    // 为每个余数维护一个单调队列，用数组模拟队列
    int* q_head = (int*)calloc(k, sizeof(int));
    int* q_tail = (int*)calloc(k, sizeof(int));
    int** q_idx = (int**)malloc(k * sizeof(int*));
    long long** q_val = (long long**)malloc(k * sizeof(long long*));
    for (int i = 0; i < k; i++) {
        q_idx[i] = (int*)malloc((2 * n + 5) * sizeof(int));
        q_val[i] = (long long*)malloc((2 * n + 5) * sizeof(long long));
    }

    // 初始：前缀下标 0，前缀和 0，余数 0
    q_val[0][q_tail[0]] = 0;
    q_idx[0][q_tail[0]] = 0;
    q_tail[0]++;

    long long prefix = 0;
    long long ans = -1000000000000000000LL;
    int found = 0;

    // 遍历复制后的数组（2n 长度），r 表示前缀和位置
    for (int r = 1; r <= 2 * n; r++) {
        prefix += nums[(r - 1) % n];
        // 处理负数取模
        int mod = (int)(prefix % k);
        if (mod < 0) mod += k;

        // 删除长度超过 n 的旧前缀和
        while (q_head[mod] < q_tail[mod] && q_idx[mod][q_head[mod]] < r - n) {
            q_head[mod]++;
        }

        // 队首是当前窗口内同余数的最小前缀和
        if (q_head[mod] < q_tail[mod]) {
            long long cur = prefix - q_val[mod][q_head[mod]];
            if (cur > ans) ans = cur;
            found = 1;
        }

        // 将当前前缀和加入单调队列，保持前缀和值单调递增
        while (q_head[mod] < q_tail[mod] && q_val[mod][q_tail[mod] - 1] >= prefix) {
            q_tail[mod]--;
        }
        q_val[mod][q_tail[mod]] = prefix;
        q_idx[mod][q_tail[mod]] = r;
        q_tail[mod]++;
    }

    // 释放动态分配的内存
    for (int i = 0; i < k; i++) {
        free(q_idx[i]);
        free(q_val[i]);
    }
    free(q_idx);
    free(q_val);
    free(q_head);
    free(q_tail);

    return found ? ans : 0;
}
